77	\begin{lemma}\leanok
78	[Exactness of the cotangent short complex]
79	  \label{lem:cotangent_exact_structure}
80	  \lean{AlgebraicGeometry.Scheme.cotangentExactSeq_structure}
81	  \uses{def:cotangent_alpha, def:cotangent_beta}
82	  The composition $\beta \circ \alpha$ vanishes, the resulting short complex is exact at the middle term, and $\beta$ is an epimorphism. The three ingredients are local statements whose ring-level inputs are the exactness of the Mathlib cotangent sequence $\Omega_{A'/A} \otimes_{A'} B \to \Omega_{B/A} \to \Omega_{B/A'} \to 0$, together with the surjectivity of the right-hand map.
83	\end{lemma}
84	
85	\begin{proof}
86	  \uses{def:cotangent_alpha, def:cotangent_beta, lem:sheafOfModules_epi_of_epi_presheaf, lem:sheafOfModules_exact_iff_stalkwise, lem:derivation_postcomp_comp, lem:cotangent_exact_seq_beta_hη}
87	  \leanok
88	  We dispose of the three claims separately.
89	
90	  \emph{Vanishing $\beta \circ \alpha = 0$.} Inject through the adjunction
91	  $\mathrm{pullback}\,f \dashv \mathrm{pushforward}\,f$, naturality of which converts the equation into one in $Y.\mathrm{Modules}$ of the form $(\hom_{\mathrm{Adj}}\alpha) \cdot (\mathrm{pushforward}\,f).\mathrm{map}\,\beta = 0$. The left-hand side unfolds via the universal property of $\mathrm{relativeDifferentials}'\,\phi$ to a Derivation-valued equality; testing against the canonical derivation $\delta_{\phi}$ reduces the equation pointwise to ``the derivation $\delta_{\phi_2'}$ vanishes on the image of the morphism of presheaves $\phi_2$'', which is the defining property of $\delta_{\phi_2'}$. The composed-adjunction coherence required for the unfolding is the equality $\phi_g' \cdot f^c = \mathrm{unit}\,\phi_{fg}'$ (which is \texttt{rfl} at the Scheme level via $(f \cdot g).c = g.c \cdot \mathrm{pushforward}(g).\mathrm{map}\,f.c$).
92	
93	  \emph{Exactness at the middle.} Exactness of a short complex of sheaves of modules is detected stalkwise: a short complex is exact iff it is exact on every stalk. On each stalk we are reduced to the ring-level exactness $\Omega_{A'/A} \otimes_{A'} B \to \Omega_{B/A} \to \Omega_{B/A'} \to 0$ provided by Mathlib's \texttt{KaehlerDifferential.exact\_mapBaseChange\_map}. The stalkwise-exactness criterion is a small Mathlib-gap-fill (Lemma~\ref{lem:sheafOfModules_exact_iff_stalkwise} below).
94	
95	  \emph{Surjectivity of $\beta$.} Epimorphism is reflected through the faithful forgetful functor $\mathrm{SheafOfModules} \to \mathrm{PresheafOfModules}$: it suffices to show $\beta.\mathrm{val}$ is an epi of presheaves. The latter follows from \texttt{PresheafOfModules.epi\_iff\_surjective} together with the fact that the descent's range contains every generator $d_{\phi_2'} b$ for $b \in \Gamma(X, U)$. Indeed, by the universal property's $\texttt{Universal.fac}$ identity, the descent sends $d_{\phi_{fg}'} b \mapsto d_{\phi_2'} b$, so $d_{\phi_2'} b$ is in the range. By Mathlib's \texttt{KaehlerDifferential.span\_range\_derivation} the span of all $d b$ equals the whole module, so the range equals $\top$, hence the descent is surjective. This argument sidesteps any explicit identification of the bundled descent with \texttt{KaehlerDifferential.map}: it works directly on generators via the universal-property collapse. The reflection step is a small Mathlib-gap-fill (Lemma~\ref{lem:sheafOfModules_epi_of_epi_presheaf} below).
96	\end{proof}
97	
98	\begin{lemma}[Stalkwise detection of exactness for sheaves of modules]
99	  \label{lem:sheafOfModules_exact_iff_stalkwise}
100	  \lean{SheafOfModules.exact_iff_stalkwise}
101	  A short complex of sheaves of $\mathcal R$-modules is exact iff its image under each stalk functor $(-)_x$ is exact in the corresponding category of modules at $x$. This transfers an exactness statement on the sheaf side to a pointwise statement on the ring-of-stalks side, where Mathlib's $\mathrm{KaehlerDifferential}$ exactness becomes directly applicable.
102	\end{lemma}
103	
104	\begin{lemma}[Epimorphism reflection from presheaves to sheaves of modules]
105	  \label{lem:sheafOfModules_epi_of_epi_presheaf}
106	  \lean{SheafOfModules.epi_of_epi_presheaf}
107	  If $f : F \to G$ is a morphism of sheaves of $\mathcal R$-modules whose underlying morphism of presheaves $f.\mathrm{val}$ is an epi, then $f$ itself is an epi. This is immediate from the faithfulness of the forgetful functor $\mathrm{SheafOfModules}\,\mathcal R \to \mathrm{PresheafOfModules}\,\mathcal R.\mathrm{val}$ combined with the general fact that faithful functors reflect epimorphisms.
108	\end{lemma}
109	
110	\begin{lemma}[Postcomposition of a derivation distributes over composition]
111	  \label{lem:derivation_postcomp_comp}
112	  \lean{PresheafOfModules.Derivation.postcomp_comp}
113	  Let $d : R \to M$ be a derivation of presheaves of $\mathcal R$-modules and let $f : M \to N$, $g : N \to P$ be morphisms of presheaves of $\mathcal R$-modules. Then
114	  \[
115	    d.\mathrm{postcomp}(f \circ g) \;=\; (d.\mathrm{postcomp}\,f).\mathrm{postcomp}\,g.
116	  \]
117	  The proof is by Derivation extensionality on each open: both sides evaluate to $g.\mathrm{app}_U \circ f.\mathrm{app}_U \circ d_U$ at section $b$. This is a Mathlib-shape lemma about $\mathrm{Derivation}'$ that is missing from Mathlib's $\mathrm{PresheafOfModules}/\mathrm{Differentials}/\mathrm{Presheaf.lean}$.
118	\end{lemma}
119	
120	\begin{lemma}\leanok
121	[Coherence square underlying the cotangent quotient $\beta$]
122	  \label{lem:cotangent_exact_seq_beta_hη}
123	  \lean{AlgebraicGeometry.Scheme.cotangentExactSeqBeta_hη}
124	  For schemes $X \xrightarrow{f} Y \xrightarrow{g} S$, there is a natural transformation
125	  \[
126	    \eta \colon (g \circ f)^{-1}\struct{S} \;\longrightarrow\; f_{*}(g^{-1}\struct{S})
127	  \]
128	  between sheaves of rings on $X$, satisfying the section-level coherence $\eta \circ \phi_{2}'^{\flat} = \phi_{fg}'^{\flat}$ where $\phi_{2}'^{\flat}$ and $\phi_{fg}'^{\flat}$ are the adjoint transposes of $f^{c}$ and $(g \circ f)^{c}$ respectively. This coherence is what packages the natural map $g \circ f \to g \circ f$ on rings into the descent map underlying $\beta$; exposing it as a top-level lemma makes the descent identification with Mathlib's $\mathrm{KaehlerDifferential.map}$ tractable.
129	\end{lemma}
130	
131	\begin{theorem}
132	
133	\leanok
134	[Cotangent exact sequence for a composition]
135	  \label{thm:cotangent_exact_sequence}
136	  \lean{AlgebraicGeometry.Scheme.cotangent_exact_sequence}
137	  \uses{def:relative_kaehler_sheaf, def:universal_derivation, def:cotangent_alpha, def:cotangent_beta, lem:cotangent_exact_structure}
138	  For schemes $X \xrightarrow{f} Y \xrightarrow{g} S$, there is an exact sequence of quasi-coherent $\struct{X}$-modules
139	  \[
140	    f^*\Omega_{Y/S} \;\xrightarrow{\;\alpha\;}\; \Omega_{X/S} \;\xrightarrow{\;\beta\;}\;
141	      \Omega_{X/Y} \;\longrightarrow\; 0,
142	  \]
143	  with $\alpha$ and $\beta$ as above. It follows by bundling the three claims of Lemma~\ref{lem:cotangent_exact_structure}.
144	\end{theorem}
145	
146	\section{Smoothness and local freeness of $\Omega$}
147	
148	\begin{theorem}\leanok
149	[Smoothness in terms of $\Omega$]
150	  \label{thm:smooth_iff_locally_free_omega}
151	  \lean{AlgebraicGeometry.Scheme.smooth_iff_locally_free_omega}
152	  \uses{def:relative_kaehler_sheaf}
153	  Let $f \colon X \to S$ be a finite-presentation morphism of schemes. Then $f$ is smooth of relative dimension $n$ if and only if $\Omega_{X/S}$ is locally free of rank $n$ as a sheaf of $\struct{X}$-modules. The forward direction is the Jacobian criterion; the converse follows from the cotangent exact sequence and Nakayama's lemma applied at each point.
154	\end{theorem}
155	
156	\begin{corollary}\leanok
157	[Cotangent space at a section]
158	  \label{cor:cotangent_at_section}
159	  \lean{AlgebraicGeometry.Scheme.cotangent_at_section}
160	  \uses{thm:smooth_iff_locally_free_omega}
161	  If $f \colon X \to S$ is smooth of relative dimension $n$ and $s \colon S \to X$ is a section of $f$, then the cotangent space $s^*\Omega_{X/S}$ is a locally free $\struct{S}$-module of rank $n$. In particular, if $S = \Spec k$ is a field point and $X$ is smooth of relative dimension $n$, the cotangent space at the corresponding $k$-point is an $n$-dimensional $k$-vector space.
162	\end{corollary}
163	
164	\section{Curves and the canonical sheaf}
165	
166	The case of a smooth proper curve $C \to \Spec k$ is the special case $n = 1$: the relative cotangent sheaf $\Omega_{C/k}$ is a line bundle on $C$, classically denoted $\omega_C$ and called the \emph{canonical sheaf}.
167	
168	\begin{theorem}\leanok
169	[Serre-duality genus equality]
170	  \label{thm:serre_duality_genus}
171	  \lean{AlgebraicGeometry.Scheme.serre_duality_genus}
172	  \uses{def:relative_kaehler_sheaf}
173	  Let $C$ be a smooth proper geometrically irreducible curve over a field $k$. Then
174	  \[
175	    \dim_k H^0(C, \Omega_{C/k}) \;=\; \dim_k H^1(C, \struct{C}).
176	  \]
177	  Both sides equal the genus $g(C)$. The equality is the dimension one case of Serre duality applied to the canonical sheaf; combined with the definition $g(C) = \dim_k H^1(C, \struct{C})$, this provides the alternative differential-theoretic characterisation used when computing the relative dimension of $\Jac(C)$ at the identity.
178	\end{theorem}
